# policies/severity_policy.py
"""
Severity classification and policy enforcement for vulnerability findings.
"""

from enum import IntEnum
from typing import List


class Severity(IntEnum):
    CRITICAL = 4
    HIGH = 3
    MEDIUM = 2
    LOW = 1
    UNKNOWN = 0

    @classmethod
    def from_string(cls, value: str) -> "Severity":
        try:
            return cls[value.upper()]
        except KeyError:
            return cls.UNKNOWN


class SeverityPolicy:
    """Defines which severity levels are blocking."""

    def __init__(self, blocking_severities: List[str] = None):
        if blocking_severities is None:
            blocking_severities = ["CRITICAL", "HIGH"]
        self.blocking_severities = [
            Severity.from_string(s) for s in blocking_severities
        ]

    def is_blocking(self, severity: str) -> bool:
        return Severity.from_string(severity) in self.blocking_severities

    def filter_blocking(self, findings: list) -> list:
        return [f for f in findings if self.is_blocking(f.severity)]

